_template:
{
  "users": [
    {% for row in rows %}
    {
      "external_user_id": "{{ row['user_id'] | default: '' }}",
      "braze_id": "{{ row['braze_user_id_latest'] | default: '' }}",
      "funnel_stage": "mau",
      "attributes": {
        "first_name": "{{ row['first_name'] | default: '' }}",
        "last_name": "{{ row['last_name'] | default: '' }}",
        "email": "{{ row['email'] | default: '' }}",
        "last_seen_at": "{{ row['last_seen_timestamp'] | default: '' }}",
        "language_tag": "{{ row['language_tag'] | default: '' }}",
        "plan_locale": "{{ row['plan_locale_latest'] | default: '' }}",
        "preferred_bible_version_id": {{ row['text_bible_version_id_latest'] | default: "null" }},
        "source_application": "{{ row['source_application'] | default: '' }}",
        "country_latest": "{{ row['country_latest'] | default: '' }}",
        "newsletter_push_enabled": {{ row['newsletter_push_enabled'] | default: true }},
        "newsletter_email_enabled": {{ row['newsletter_email_enabled'] | default: true }}
      }
    }{% unless forloop.last %},{% endunless %}
    {% endfor %}
  ]
}
